long long solve(std::vector<long long> nums, std::vector<std::vector<long long>> queries) {
    // Precompute popcount-depth for each number in nums
    std::vector<int> popcount_depths;
    for (long long num : nums) {
        int depth = 0;
        long long current = num;
        while (current > 0) {
            current = __builtin_popcountll(current);
            depth++;
        }
        popcount_depths.push_back(depth);
    }

    // Build a frequency map for each depth
    std::unordered_map<int, std::vector<int>> depth_map;
    for (int i = 0; i < nums.size(); ++i) {
        depth_map[popcount_depths[i]].push_back(i);
    }

    // Process queries
    std::vector<long long> answer;
    for (auto& query : queries) {
        if (query[0] == 1) {
            // Query type 1: count numbers in [l, r] with depth k
            int l = query[1], r = query[2], k = query[3];
            long long count = 0;
            if (depth_map.find(k) != depth_map.end()) {
                const std::vector<int>& indices = depth_map[k];
                // Use binary search to find the count in [l, r]
                auto it1 = std::lower_bound(indices.begin(), indices.end(), l);
                auto it2 = std::upper_bound(indices.begin(), indices.end(), r);
                count = std::distance(it1, it2);
            }
            answer.push_back(count);
        } else {
            // Query type 2: update nums[idx] to val
            int idx = query[1], val = query[2];
            nums[idx] = val;
            // Recompute popcount-depth for the updated number
            int new_depth = 0;
            long long current = val;
            while (current > 0) {
                current = __builtin_popcountll(current);
                new_depth++;
            }
            // Update the depth map
            int old_depth = popcount_depths[idx];
            auto it = std::find(depth_map[old_depth].begin(), depth_map[old_depth].end(), idx);
            if (it != depth_map[old_depth].end()) {
                depth_map[old_depth].erase(it);
            }
            depth_map[new_depth].push_back(idx);
            popcount_depths[idx] = new_depth;
        }
    }

    return answer;
}

